        body {
            background: #0b0f1a;
            font-family: 'Segoe UI', system-ui, 'Helvetica Neue', sans-serif;
            display: flex;
            justify-content: center;
            padding: 2rem 1rem;
            margin: 0;
            color: #e0e6f0;
        }
        .card {
            max-width: 780px;
            background: #141b2b;
            border-radius: 28px;
            padding: 2rem 2.2rem;
            box-shadow: 0 12px 40px rgba(0, 0, 0, 0.7), 0 0 0 1px #2a3a5c;
            border: 1px solid #3f557a;
            transition: 0.2s;
        }
        .card:hover {
            box-shadow: 0 18px 48px #0f1625, 0 0 0 1px #5c7bb5;
        }
        h2, p {
            margin: 0 0 1rem 0;
            line-height: 1.5;
        }
        .glow {
            color: #fcdb5e;
            text-shadow: 0 0 6px #f0b33c;
        }
        .highlight {
            background: #1f2b44;
            padding: 0.15rem 0.6rem;
            border-radius: 12px;
            font-weight: 600;
            color: #b7d0ff;
            border: 1px solid #3f5b8a;
        }
